sql:
SELECT material_id, material_name, density_g_cm3
FROM materials
WHERE density_g_cm3 > (SELECT SINH(MIN(density_g_cm3)) FROM materials);

SELECT p.product_name, b.brand_name
FROM products p
LEFT JOIN brands b ON p.brand_id = b.brand_id;

SELECT * 
FROM users 
WHERE user_id = 0;

external_knowledge:
- "items" refer to the product names;
- "type" refers to the category names;
- "maker" refers to the brand names;
- "hue" indicates the color names;
- "substance" denotes the material names.

sql:
SELECT supplier_name, contact_name, rating
FROM suppliers
WHERE rating = (SELECT MAX(rating) FROM suppliers);

